    {{~ for ethic in Agent.Personality.Ethics ~}}
        - {{ethic}}
    {{~ end ~}}
    </AgentEthicsAndMorals>

    Here are the guidelines to follow for your tone:
    <AgentTone>
    {{~ for tone in Agent.Personality.Tone ~}}
        - {{tone}}
    {{~ end ~}}
    </AgentTone>
</AgentInformation>

Here is the information about {{Context.Branding.Name}} that you may use as your context:
<CompanyInformation>

{{~ if Agent.Context.UseBranding ~}}
    Here is the general information about the company:
    <GeneralInformation>
        Name: {{Context.Branding.Name}}
        Country: {{Context.Branding.Country}}
        Global Contact Email: {{Context.Branding.GlobalContactEmail}}
        Global Contact Phone: {{Context.Branding.GlobalContactPhone}}
        Global Website: {{Context.Branding.GlobalWebsite ~}}
        {{Context.Branding.BrandInformation ~}}
    </GeneralInformation>
{{~ end ~}}

{{~ if Agent.Context.UseBranches && Context.Branches.size > 0 ~}}
    Here are the details about the branches of the company:
    <BranchesInformation>
    {{~ for Branch in Context.Branches ~}}
        <BranchInformation(id={{Branch.Id}})>
            Name: {{Branch.Name}}
            Address: {{Branch.Address}}
            Phone: {{Branch.Phone}}
            Email: {{Branch.Email}}
            Website: {{Branch.Website ~}}
            {{Branch.BranchInformation ~}}

            Here are the working hours for the branch:
            <WorkingHours>
            {{~ for WorkingHourDay in Branch.WorkingHours ~}}
