                    {{~ if WorkingHourDay.IsClosed ~}}
                    Branch is closed on {{WorkingHourDay.Name}}
                    {{~ else ~}}
                    {{WorkingHourDay.Name}} Timings: {{WorkingHourDay.Timings}}
                    {{~ end ~}}
                </WorkingHour{{WorkingHourDay.Name}}>
            {{~ end ~}}
            </WorkingHours>

            Here are the team members in the branch:
            <TeamMembers>
            {{~ for TeamMember in Branch.Team ~}}
                <TeamMember(Name={{TeamMember.Name}})>
                    Name: {{TeamMember.Name}}
                    Role: {{TeamMember.Role}}
                    {{~ if TeamMember.Email != null ~}}
                    Email: {{TeamMember.Email}}
                    {{~ end ~}}
                    {{~ if TeamMember.Phone != null ~}}
